// Determine report type and date range
const now = new Date();
const isMonthly = $input.first()?.json?.report_type === 'monthly' || 
                  now.getDate() <= 7; // First week = monthly report

const reportType = isMonthly ? 'monthly' : 'weekly';

// Calculate date ranges
let dateFrom, dateTo, reportName;

if (reportType === 'weekly') {
  // Last 7 days
  dateTo = new Date(now);
  dateFrom = new Date(now);
  dateFrom.setDate(dateFrom.getDate() - 7);
  reportName = `Weekly Report - ${dateFrom.toLocaleDateString()} to ${dateTo.toLocaleDateString()}`;
} else {
  // Previous month
  dateTo = new Date(now.getFullYear(), now.getMonth(), 0);
  dateFrom = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  reportName = `Monthly Report - ${dateFrom.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}`;
}

return {
  json: {
    report_type: reportType,
    report_name: reportName,
    date_from: dateFrom.toISOString(),
    date_to: dateTo.toISOString(),
    generated_at: now.toISOString(),
    recipients: [
      'team@lemonade.ai',
      'engineering@lemonade.ai'
    ].filter(Boolean)
  }
};

// Aggregate all report data
const runStats = $node["Fetch Run Stats"].json?.data || {};
const runs = ($node["Fetch Recent Runs"].json?.data || []).filter(r => {
  const runDate = new Date(r.created_at);
  const dateFrom = new Date($node["Determine Report Type"].json.date_from);
  const dateTo = new Date($node["Determine Report Type"].json.date_to);
  return runDate >= dateFrom && runDate <= dateTo;
});
const models = $node["Fetch Models"].json?.data || [];
const aggregateMetrics = $node["Fetch Aggregate Metrics"].json?.data || [];

// Calculate summary statistics
const totalRuns = runs.length;
const completedRuns = runs.filter(r => r.status === 'completed').length;
const failedRuns = runs.filter(r => r.status === 'failed').length;
const successRate = totalRuns > 0 ? (completedRuns / totalRuns * 100).toFixed(1) : 0;

// Group runs by type
const runsByType = runs.reduce((acc, r) => {
  acc[r.run_type] = (acc[r.run_type] || 0) + 1;
  return acc;
}, {});

// Group runs by status
const runsByStatus = runs.reduce((acc, r) => {
  acc[r.status] = (acc[r.status] || 0) + 1;
  return acc;
}, {});

// Group runs by device
const runsByDevice = runs.reduce((acc, r) => {
  acc[r.device || 'unknown'] = (acc[r.device || 'unknown'] || 0) + 1;
  return acc;
}, {});

// Calculate average duration
const avgDuration = runs.filter(r => r.duration_seconds)
  .reduce((acc, r) => acc + r.duration_seconds, 0) / (runs.filter(r => r.duration_seconds).length || 1);

// Top models by runs
const modelRunCounts = runs.reduce((acc, r) => {
  const modelName = r.model?.name || 'Unknown';
  acc[modelName] = (acc[modelName] || 0) + 1;
  return acc;
}, {});
const topModels = Object.entries(modelRunCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => ({ name, count }));

// Performance summary from aggregate metrics
const performanceSummary = aggregateMetrics
  .filter(m => m.category === 'performance')
  .map(m => ({
    name: m.name,
    mean: m.mean?.toFixed(2),
    unit: m.unit,
    min: m.min?.toFixed(2),
    max: m.max?.toFixed(2)
  }));

return {
  json: {
    report_data: {
      title: $node["Determine Report Type"].json.report_name,
      report_type: $node["Determine Report Type"].json.report_type,
      period: {
        from: $node["Determine Report Type"].json.date_from,
        to: $node["Determine Report Type"].json.date_to
      },
      generated_at: $node["Determine Report Type"].json.generated_at,
      summary: {
        total_runs: totalRuns,
        completed_runs: completedRuns,
        failed_runs: failedRuns,
        success_rate: `${successRate}%`,
        average_duration_seconds: Math.round(avgDuration),
        total_models: models.length,
        unique_checkpoints: new Set(runs.map(r => r.build_name)).size
      },
      runs_by_type: runsByType,
      runs_by_status: runsByStatus,
      runs_by_device: runsByDevice,
      top_models: topModels,
      performance_metrics: performanceSummary,
      run_stats: runStats
    }
  }
};

